    <polyline points="80,90 160,130 240,110 320,175 400,160 480,220 560,205 640,215" fill="none" stroke="#f87171" stroke-width="3"/>
    <text x="240" y="100" fill="#f87171" font-size="13" text-anchor="middle" font-family="sans-serif">Chute 9 nov 17 592$</text>
    <text x="560" y="240" fill="#f87171" font-size="13" text-anchor="middle" font-family="sans-serif">Plus bas 21 nov 15 476$</text>
    <circle cx="320" cy="175" r="5" fill="#f87171"/>
